 1→/*
 2→ * test-atan.c -- atan() and atanf()
 3→ */
 4→#include "test-common.h"
 5→
 6→static const double din[] = {
 7→    0.0, -0.0, 1e-300, -1e-300, 5e-324, 1e-15, -1e-15,
 8→    0.1, 0.5, 1.0, 2.0, 10.0, 100.0, 1e10,
 9→    -0.1, -0.5, -1.0, -2.0, -10.0, -100.0, -1e10,
10→    /* near 1 */
11→    0.999999999, 1.000000001,
12→};
13→#define DIN_COUNT (sizeof(din)/sizeof(din[0]))
14→
15→static const float fin[] = {
16→    0.0f, -0.0f, 1e-38f, 1.4e-45f,
17→    0.1f, 0.5f, 1.0f, 2.0f, 10.0f, 100.0f, 1e10f,
18→    -0.1f, -0.5f, -1.0f, -2.0f, -10.0f, -100.0f,
19→};
20→#define FIN_COUNT (sizeof(fin)/sizeof(fin[0]))
21→
22→int main(void)
23→{
24→    unsigned i;
25→    for (i = 0; i < DIN_COUNT; i++)
26→        P_D1(atan, din[i]);
27→    P_D1(atan, INFINITY);
28→    P_D1(atan, -INFINITY);
29→    P_D1(atan, NAN);
30→
31→    for (i = 0; i < FIN_COUNT; i++)
32→        P_F1(atanf, fin[i]);
33→    P_F1(atanf, INFINITY);
34→    P_F1(atanf, -INFINITY);
35→    P_F1(atanf, NAN);
36→
37→    return 0;
38→}
